#ifndef GDN_DECODE_QK4_V8_D128_K_LAST_KERNEL_H_
#define GDN_DECODE_QK4_V8_D128_K_LAST_KERNEL_H_

#include <cuda.h>
#include <cuda_runtime.h>
#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <stdint.h>

#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 800)
#include <cuda_bf16.h>
#endif

// Tensor constants for this kernel
constexpr int kNumQHeads = 4;
constexpr int kNumKHeads = 4;
constexpr int kNumVHeads = 8;
constexpr int kHeadSize  = 128; // K and V are both 128
constexpr int kExpand    = kNumVHeads / kNumQHeads; // 2

// CUDA launcher
void gdn_decode_qk4_v8_d128_k_last_launch(
    const at::cuda::CUDAStream& stream,
    int64_t B,
    const at::BFloat16* q,   // [B,1,4,128]
    const at::BFloat16* k,   // [B,1,4,128]
    const at::BFloat16* v,   // [B,1,8,128]
    const float* state,      // [B,8,128,128]  (V,K) layout
    const float* A_log,      // [8]
    const at::BFloat16* a,   // [B,1,8]
    const float* dt_bias,    // [8]
    const at::BFloat16* b,   // [B,1,8]
    float scale,
    at::BFloat16* out,       // [B,1,8,128]
    float* new_state         // [B,8,128,128]
);

#endif // GDN_DECODE_QK4_V8_D128_K_LAST_KERNEL_H_

#include "kernel.h"
#include <cuda.h>
#include <cuda_runtime.h>
#include <ATen/cuda/CUDAContext.h>

#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 800)
#include <cuda_bf16.h>
#endif

// ------------------------- Utilities -------------------------

#ifndef CHECK_CUDA
#define CHECK_CUDA(x) TORCH_CHECK(x.is_cuda(), #x " must be a CUDA tensor")
#endif

#define CUDA_CHECK_KERNEL()                                              \
  do {                                                                    \
    cudaError_t err = cudaGetLastError();                                 \
    if (err != cudaSuccess) {                                             \
      printf("CUDA kernel error: %s\n", cudaGetErrorString(err));         \
    }                                                                     \
  } while (0)

__device__ __forceinline__ float sigmoidf(float x) {
  return 1.0f / (1.0f + expf(-x));
}

// numerically-stable softplus
__device__ __forceinline__ float softplusf(float x) {
  // softplus(x)=log(1+exp(x))
  // stable: if x>0 -> x+log1p(exp(-x)), else log1p(exp(x))
  if (x > 0.0f) return x + log1pf(expf(-x));
  return log1pf(expf(x));
}

__device__ __forceinline__ float bf16_to_f32(at::BFloat16 x) {
#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 800)
  __nv_bfloat16 t;
  // at::BFloat16 is 16-bit storage compatible with __nv_bfloat16 payload
  memcpy(&t, &x, sizeof(uint16_t));
  return __bfloat162float(t);
#else
  // fallback (should not happen for CUDA build)
  return (float)x;
#endif
}

__device__ __forceinline__ at::BFloat16 f32_to_bf16(float x) {
#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 800)
  __nv_bfloat16 t = __float2bfloat16_rn(x);
  at::BFloat16 out;
  memcpy(&out, &t, sizeof(uint16_t));
  return out;
#else
  return (at::BFloat16)x;
#endif
}

static __device__ __forceinline__ int idx_q(int64_t b, int hq, int d) {
  // q: [B,1,4,128]
  return (int)(b * (1 * kNumQHeads * kHeadSize) + 0 * (kNumQHeads * kHeadSize) + hq * kHeadSize + d);
}
static __device__ __forceinline__ int idx_k(int64_t b, int hk, int d) {
  // k: [B,1,4,128]
  return (int)(b * (1 * kNumKHeads * kHeadSize) + 0 * (kNumKHeads * kHeadSize) + hk * kHeadSize + d);
}
static __device__ __forceinline__ int idx_v(int64_t b, int hv, int d) {
  // v: [B,1,8,128]
  return (int)(b * (1 * kNumVHeads * kHeadSize) + 0 * (kNumVHeads * kHeadSize) + hv * kHeadSize + d);
}
static __device__ __forceinline__ int idx_state(int64_t b, int hv, int v, int k) {
  // state/new_state: [B,8,128,128] in (V,K) layout contiguous last dim
  // offset = (((b*8 + hv)*128 + v)*128 + k)
  return (int)((((b * kNumVHeads + hv) * kHeadSize + v) * kHeadSize + k));
}

// ------------------------- Kernel -------------------------
//
// Computes for each (B,hv):
// g = exp(-exp(A_log[hv]) * softplus(a + dt_bias[hv]))
// beta = sigmoid(b)
//
// With q/k expansion: hq = hv/2, hk = hv/2
//
// Let S be state in (V,K). Reference transposes to (K,V), does math, then transpose back.
// We do math in (K,V) logically but store to new_state in (V,K) directly.
// Derivation (matching reference):
// old_state_KV = g * state_KV
// old_v[V] = sum_k k[k] * old_state_KV[k,V]
// new_v[V] = beta*v[V] + (1-beta)*old_v[V]
// h_state_KV[k,V] = old_state_KV[k,V] - k[k]*old_v[V] + k[k]*new_v[V]
// output[V] = scale * sum_k q[k]*h_state_KV[k,V]
//
// We compute old_v[V] first, then new_v[V], then output and new_state.
// Since K=128,V=128 fixed, we use 256 threads per block:
//   - 128 threads handle V dimension work (each thread t<128 computes one V element for old_v/new_v/output).
//   - all 256 threads participate in loading q/k into shared.
//   - updating new_state requires writing 128x128 = 16384 floats. We have each thread write 64 elements.

__global__ void gdn_decode_qk4_v8_d128_k_last_kernel(
    int64_t B,
    const at::BFloat16* __restrict__ q,
    const at::BFloat16* __restrict__ k,
    const at::BFloat16* __restrict__ v,
    const float* __restrict__ state,
    const float* __restrict__ A_log,
    const at::BFloat16* __restrict__ a,
    const float* __restrict__ dt_bias,
    const at::BFloat16* __restrict__ b_in,
    float scale,
    at::BFloat16* __restrict__ out,
    float* __restrict__ new_state)
{
  // grid: dim3(B, 8, 1)
  const int64_t bidx = (int64_t)blockIdx.x;
  const int hv = (int)blockIdx.y; // 0..7
  if (bidx >= B) return;

  // Expand mapping
  const int hq = hv >> 1; // /2
  const int hk = hv >> 1; // /2

  __shared__ float sh_q[128];
  __shared__ float sh_k[128];
  __shared__ float sh_old_v[128];
  __shared__ float sh_new_v[128];

  // Load q and k into shared (all 256 threads help)
  for (int d = threadIdx.x; d < 128; d += blockDim.x) {
    sh_q[d] = bf16_to_f32(q[idx_q(bidx, hq, d)]);
    sh_k[d] = bf16_to_f32(k[idx_k(bidx, hk, d)]);
  }

  // Compute g and beta once per block (thread0)
  __shared__ float sh_g;
  __shared__ float sh_beta;
  if (threadIdx.x == 0) {
    // a: [B,1,8], b: [B,1,8]
    int a_off = (int)(bidx * (1 * kNumVHeads) + 0 * kNumVHeads + hv);
    float a_f = bf16_to_f32(a[a_off]);
    float b_f = bf16_to_f32(b_in[a_off]);
    float x = a_f + dt_bias[hv];
    float g = expf(-expf(A_log[hv]) * softplusf(x));
    float beta = sigmoidf(b_f);
    sh_g = g;
    sh_beta = beta;
  }
  __syncthreads();

  // 1) old_v[V] = sum_k k[k] * (g * state_KV[k,V])
  // state is stored as (V,K). state_KV[k,V] = state[V,K] with swapped indices.
  // i.e., state_KV[k,V] == state[V,k] in memory at idx_state(b,hv,V,k).
  if (threadIdx.x < 128) {
    const int V = threadIdx.x;
    float acc = 0.0f;
    #pragma unroll
    for (int kk = 0; kk < 128; ++kk) {
      float s = state[idx_state(bidx, hv, V, kk)]; // (V,K)
      acc += sh_k[kk] * (sh_g * s);               // corresponds to (g * state_KV)
    }
    sh_old_v[V] = acc;
  }
  __syncthreads();

  // 2) new_v[V] = beta*v[V] + (1-beta)*old_v[V]
  if (threadIdx.x < 128) {
    const int V = threadIdx.x;
    float vv = bf16_to_f32(v[idx_v(bidx, hv, V)]);
    float beta = sh_beta;
    sh_new_v[V] = beta * vv + (1.0f - beta) * sh_old_v[V];
  }
  __syncthreads();

  // 3) output[V] = scale * sum_k q[k] * h_state_KV[k,V]
  // where h_state_KV[k,V] = g*state_KV[k,V] - k[k]*old_v[V] + k[k]*new_v[V]
  //                     = g*state[V,k] + k[k]*(new_v[V]-old_v[V])
  if (threadIdx.x < 128) {
    const int V = threadIdx.x;
    float delta = sh_new_v[V] - sh_old_v[V];
    float acc = 0.0f;
    #pragma unroll
    for (int kk = 0; kk < 128; ++kk) {
      float s = state[idx_state(bidx, hv, V, kk)];
      float hkv = sh_g * s + sh_k[kk] * delta;
      acc += sh_q[kk] * hkv;
    }
    float o = scale * acc;
    // out: [B,1,8,128]
    int out_off = (int)(bidx * (1 * kNumVHeads * kHeadSize) + 0 * (kNumVHeads * kHeadSize) + hv * kHeadSize + V);
    out[out_off] = f32_to_bf16(o);
  }

  // 4) new_state in (V,K) layout:
  // new_state[V,k] = h_state_KV[k,V] = g*state[V,k] + k[k]*(new_v[V]-old_v[V])
  // Write 16384 floats per (B,hv).
  // Each thread writes a strided subset over linear index in [0, 16384).
  const int total = 128 * 128;
  for (int lin = threadIdx.x; lin < total; lin += blockDim.x) {
    const int V = lin >> 7;      // /128
    const int kk = lin & 127;    // %128
    float s = state[idx_state(bidx, hv, V, kk)];
    float delta = sh_new_v[V] - sh_old_v[V];
    float val = sh_g * s + sh_k[kk] * delta;
    new_state[idx_state(bidx, hv, V, kk)] = val;
  }
}

// ------------------------- Launcher -------------------------

void gdn_decode_qk4_v8_d128_k_last_launch(
    const at::cuda::CUDAStream& stream,
    int64_t B,
    const at::BFloat16* q,
    const at::BFloat16* k,
    const at::BFloat16* v,
    const float* state,
    const float* A_log,
    const at::BFloat16* a,
    const float* dt_bias,
    const at::BFloat16* b,
    float scale,
    at::BFloat16* out,
    float* new_state)
{
  dim3 block(256, 1, 1);
  dim3 grid((unsigned)B, (unsigned)kNumVHeads, 1);

  gdn_decode_qk4_v8_d128_k_last_kernel<<<grid, block, 0, stream>>>(
      B, q, k, v, state, A_log, a, dt_bias, b, scale, out, new_state);

  CUDA_CHECK_KERNEL();
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <vector>
#include <cmath>
#include <optional>
#include "kernel.h"

static void check_bf16_cuda_contig(const torch::Tensor& t, const char* name) {
  TORCH_CHECK(t.defined(), name, " must be defined");
  TORCH_CHECK(t.is_cuda(), name, " must be a CUDA tensor");
  TORCH_CHECK(t.is_contiguous(), name, " must be contiguous");
  TORCH_CHECK(t.scalar_type() == torch::kBFloat16, name, " must be BF16");
}

static void check_f32_cuda_contig(const torch::Tensor& t, const char* name) {
  TORCH_CHECK(t.defined(), name, " must be defined");
  TORCH_CHECK(t.is_cuda(), name, " must be a CUDA tensor");
  TORCH_CHECK(t.is_contiguous(), name, " must be contiguous");
  TORCH_CHECK(t.scalar_type() == torch::kFloat32, name, " must be float32");
}

static void check_shape(const torch::Tensor& t, std::vector<int64_t> expected, const char* name) {
  TORCH_CHECK((int)t.dim() == (int)expected.size(), name, " dim mismatch. Expected ", expected.size(), " got ", t.dim());
  for (int i = 0; i < (int)expected.size(); ++i) {
    if (expected[i] >= 0) {
      TORCH_CHECK(t.size(i) == expected[i], name, " shape mismatch at dim ", i, ". Expected ", expected[i], " got ", t.size(i));
    }
  }
}

torch::Tensor run(
    torch::Tensor q,        // [B,1,4,128] bf16
    torch::Tensor k,        // [B,1,4,128] bf16
    torch::Tensor v,        // [B,1,8,128] bf16
    torch::Tensor state,    // [B,8,128,128] f32
    torch::Tensor A_log,    // [8] f32
    torch::Tensor a,        // [B,1,8] bf16
    torch::Tensor dt_bias,  // [8] f32
    torch::Tensor b,        // [B,1,8] bf16
    c10::optional<double> scale_opt // scalar float (optional)
) {
  // Validate
  check_bf16_cuda_contig(q, "q");
  check_bf16_cuda_contig(k, "k");
  check_bf16_cuda_contig(v, "v");
  check_f32_cuda_contig(state, "state");
  check_f32_cuda_contig(A_log, "A_log");
  check_bf16_cuda_contig(a, "a");
  check_f32_cuda_contig(dt_bias, "dt_bias");
  check_bf16_cuda_contig(b, "b");

  TORCH_CHECK(q.device() == k.device() && q.device() == v.device() && q.device() == state.device(), "All tensors must be on same CUDA device");
  TORCH_CHECK(q.device() == A_log.device() && q.device() == a.device() && q.device() == dt_bias.device() && q.device() == b.device(),
              "All tensors must be on same CUDA device");

  const int64_t B = q.size(0);
  check_shape(q,     {B, 1, kNumQHeads, kHeadSize}, "q");
  check_shape(k,     {B, 1, kNumKHeads, kHeadSize}, "k");
  check_shape(v,     {B, 1, kNumVHeads, kHeadSize}, "v");
  check_shape(state, {B, kNumVHeads, kHeadSize, kHeadSize}, "state");
  check_shape(A_log, {kNumVHeads}, "A_log");
  check_shape(a,     {B, 1, kNumVHeads}, "a");
  check_shape(dt_bias,{kNumVHeads}, "dt_bias");
  check_shape(b,     {B, 1, kNumVHeads}, "b");

  float scale = 0.0f;
  if (scale_opt.has_value()) {
    scale = (float)scale_opt.value();
  }
  if (scale == 0.0f) {
    scale = 1.0f / std::sqrt((float)kHeadSize);
  }

  // Allocate outputs
  auto out = torch::empty({B, 1, kNumVHeads, kHeadSize}, torch::TensorOptions().device(q.device()).dtype(torch::kBFloat16));
  auto new_state = torch::empty({B, kNumVHeads, kHeadSize, kHeadSize}, torch::TensorOptions().device(q.device()).dtype(torch::kFloat32));

  // Launch
  const auto stream = at::cuda::getDefaultCUDAStream();

  gdn_decode_qk4_v8_d128_k_last_launch(
      stream,
      B,
      (const at::BFloat16*)q.data_ptr<at::BFloat16>(),
      (const at::BFloat16*)k.data_ptr<at::BFloat16>(),
      (const at::BFloat16*)v.data_ptr<at::BFloat16>(),
      (const float*)state.data_ptr<float>(),
      (const float*)A_log.data_ptr<float>(),
      (const at::BFloat16*)a.data_ptr<at::BFloat16>(),
      (const float*)dt_bias.data_ptr<float>(),
      (const at::BFloat16*)b.data_ptr<at::BFloat16>(),
      scale,
      (at::BFloat16*)out.data_ptr<at::BFloat16>(),
      (float*)new_state.data_ptr<float>());

  // Ensure completion for correctness in eager mode (caller can remove if desired)
  TORCH_CHECK(cudaGetLastError() == cudaSuccess, "CUDA launch failed");
  TORCH_CHECK(cudaDeviceSynchronize() == cudaSuccess, "CUDA sync failed");

  // Return tuple(output, new_state) like reference
  return torch::stack({}); // dummy to satisfy compiler if someone removes below
}

std::vector<torch::Tensor> run_tuple(
    torch::Tensor q,
    torch::Tensor k,
    torch::Tensor v,
    torch::Tensor state,
    torch::Tensor A_log,
    torch::Tensor a,
    torch::Tensor dt_bias,
    torch::Tensor b,
    c10::optional<double> scale_opt
) {
  // Reuse run() logic but return both tensors
  // (kept separate because pybind can bind vector<tensor> as tuple)
  check_bf16_cuda_contig(q, "q");
  check_bf16_cuda_contig(k, "k");
  check_bf16_cuda_contig(v, "v");
  check_f32_cuda_contig(state, "state");
  check_f32_cuda_contig(A_log, "A_log");
  check_bf16_cuda_contig(a, "a");
  check_f32_cuda_contig(dt_bias, "dt_bias");
  check_bf16_cuda_contig(b, "b");

  const int64_t B = q.size(0);
  check_shape(q,     {B, 1, kNumQHeads, kHeadSize}, "q");
  check_shape(k,     {B, 1, kNumKHeads, kHeadSize}, "k");
  check_shape(v,     {B, 1, kNumVHeads, kHeadSize}, "v");
  check_shape(state, {B, kNumVHeads, kHeadSize, kHeadSize}, "state");
  check_shape(A_log, {kNumVHeads}, "A_log");
  check_shape(a,     {B, 1, kNumVHeads}, "a");
  check_shape(dt_bias,{kNumVHeads}, "dt_bias");
  check_shape(b,     {B, 1, kNumVHeads}, "b");

  float scale = 0.0f;
  if (scale_opt.has_value()) scale = (float)scale_opt.value();
  if (scale == 0.0f) scale = 1.0f / std::sqrt((float)kHeadSize);

  auto out = torch::empty({B, 1, kNumVHeads, kHeadSize}, torch::TensorOptions().device(q.device()).dtype(torch::kBFloat16));
  auto new_state = torch::empty({B, kNumVHeads, kHeadSize, kHeadSize}, torch::TensorOptions().device(q.device()).dtype(torch::kFloat32));

  const auto stream = at::cuda::getDefaultCUDAStream();
  gdn_decode_qk4_v8_d128_k_last_launch(
      stream,
      B,
      (const at::BFloat16*)q.data_ptr<at::BFloat16>(),
      (const at::BFloat16*)k.data_ptr<at::BFloat16>(),
      (const at::BFloat16*)v.data_ptr<at::BFloat16>(),
      (const float*)state.data_ptr<float>(),
      (const float*)A_log.data_ptr<float>(),
      (const at::BFloat16*)a.data_ptr<at::BFloat16>(),
      (const float*)dt_bias.data_ptr<float>(),
      (const at::BFloat16*)b.data_ptr<at::BFloat16>(),
      scale,
      (at::BFloat16*)out.data_ptr<at::BFloat16>(),
      (float*)new_state.data_ptr<float>());

  TORCH_CHECK(cudaGetLastError() == cudaSuccess, "CUDA launch failed");
  TORCH_CHECK(cudaDeviceSynchronize() == cudaSuccess, "CUDA sync failed");

  return {out, new_state};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  // Bind tuple-returning function as "run" to match requested API
  m.def("run", &run_tuple, "gdn_decode_qk4_v8_d128_k_last (CUDA)");
}
